import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "窗。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他醒來的第一個動作，不是摸手機。不是摸口袋。不是摸胸口。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他衝到窗邊。拉開窗簾。推開窗。冷空氣灌進來——帶著雨的、帶著海的、帶著清晨泥土味道的、乾淨的、可以大口吸進去的冷空氣。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他呼吸。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "深。用力。一次。兩次。三次。四次。每一次吸進去的空氣都像水一樣灌滿了乾涸的肺。沒有油味。沒有塑膠味。沒有悶熱。沒有那種從通風口壓進來的、看不見的、黏稠的東西。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他不是在享受新鮮空氣。他是在確認自己還能呼吸。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不是醫務室。", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)窗外是宿舍。天空是灰的。雨是細的。海在遠處。我在四樓。不是內間。不是地上。不是那扇被膠帶封死的窗戶背後。", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他關上窗。雨聲變成了一層安靜的、均勻的背景音。和每一輪一樣。和每一次醒來一樣。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走回床邊。手機亮著。07:05。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第四次了。", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第一輪。鐘樓。第二輪。校務車。第三輪。醫務室。第四次醒來。", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有崩潰。沒有發抖。沒有蹲在地上抱著頭。他坐在床沿上，兩腳踩著冰涼的地板，兩手放在膝蓋上，脊背挺直，像一個被重置過但保留了所有存檔數據的系統。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不一樣了。", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第一輪醒來——恐懼。不知道發生了什麼。第二輪醒來——震驚。發現記憶留著。第三輪醒來——冷靜。開始測試。第四輪——", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第四輪我不再問「為什麼是我」。", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我問的是「下一步查什麼」。", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站起來。走到書桌前。拉開抽屜——空的。上一輪寫的東西不會在。他從桌面拿起一支筆。抽出一張白紙。坐下。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他開始寫。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這一次他寫的不是「哪裡會死」。不是逃生路線。不是恐懼和死亡的筆記。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他畫了一張表格。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "橫軸是三個欄位：第一輪、第二輪、第三輪。縱軸是五個項目。他用非常工整、非常小的字體填寫，像在寫一份報告。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第一行：「地點」。下面三格分別寫了：鐘樓、後山維修路、醫務室。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第二行：「表面危險」。下面三格：停電墜落、車輛事故、局部停電與廢氣。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第三行：「共通物」。下面三格分別寫了：灰色膠帶、黑雨衣、相機；黑色相機包、車輛表；南翼門禁、設備區、灰色膠帶。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第四行：「控制來源」。下面三格：門禁／電力、車輛／路線、指揮室／醫務室／校安。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第五行：「監控」。三格全部寫了同一個詞：空白。在最後一格的旁邊，他加了一行小字：十七分鐘。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)三次。三個不同的地方。三種不同的死法。", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但控制來源有共同點。", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第一輪——門禁和電力。誰管門禁和電力？行政組。誰能決定鐘樓什麼時候停電？第二輪——車輛和路線。誰管車輛進出表？誰能臨時改備用路線？第三輪——指揮室、醫務室、校安。誰在指揮室裡？誰安排我去醫務室？誰對校安說「先讓他待著」？", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)答案全部指向同一個地方。", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他在表格下方，寫了一段話。字跡比表格更小。更用力。筆尖幾乎把紙壓穿了。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「我測不到邵叔是不是兇手。他這一輪做的每件事都可以解釋成保護。封鐘樓——合理。停車——合理。安排醫務室——合理。連他聽到『相機』時停頓的那半秒，都可以解釋成一個警察在思考。」", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「但我測到了一件事。」", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「只要我把線索交到指揮室，我就會被安排到一個新的死角。」", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第一輪——我把訊息完整交給邵叔。當晚死在鐘樓。第二輪——我避開邵叔。死在後山。第三輪——我只給邵叔一半線索，讓他動起來，觀察他的反應。他確實封了鐘樓、停了車——前兩輪的死亡路線全被他堵上了。但我死在了他安排我去的地方。", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不是因為邵叔一定是兇手。而是因為——線索一旦進入指揮系統，就會被那個系統裡的人重新分配。結果就是——我每一次都被送到一個出不來的地方。", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)是誰在分配？不知道。但分配的權限在指揮室裡。", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他放下筆。吸了一口氣。窗外的雨聲沒有變。07:07。廣播還沒有響。世界還沒有開始今天的劇本。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不是找哪裡安全。", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)是查誰能把安全地方變成死角。", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把這句話也寫在了紙上。寫在表格的正下方。寫完之後他盯著這行字看了五秒。然後在下面又加了一句：", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「控制門的人。控制車的人。控制監控的人。控制路線的人。控制醫務室的人。」", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「所有這些控制權，集中在哪裡？」", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「指揮室。」", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他拿起手機。07:08。窗外，廣播響了。那個女聲。那份百年校慶提醒稿。第四次聽了。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我知道訊息會說什麼。「今晚 22:22，鐘樓會停電。不要上去。不要把相機交給任何大人。」", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這一次我不需要它來告訴我危險在哪裡。我已經知道危險不在任何一個固定地點。", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)危險在流程裡。在指揮室裡。在那個能把每一扇安全門變成牢門的人的手裡。", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "07:09。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把紙折好。放進校服的胸前口袋。他知道這張紙到下一輪不會還在。但他還是放了。像一個儀式。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "07:12。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "手機震動。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "訊息來了。他知道是什麼。從哪個號碼。什麼內容。每一個字。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但這一次，顧言沒有先看訊息。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他先拿起筆，在白紙的最下方，寫下了四個字。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "字跡很大。很重。像刻進去的。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "**指揮室。**", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他才拿起手機。點開訊息。一個字一個字地看過去。和前三次一模一樣的訊息。和前三次一模一樣的 07:12。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但他讀這條訊息的方式，已經完全不同了。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第一輪。我把你交給了錯的人。", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第二輪。我藏著你，一個人跑。", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第三輪。我拿你的一半去試探。", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第四輪。", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這一次，我不跑。不試探。不交給任何人。", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這一次，我要查清楚——是誰，在指揮室裡，把每一條我走過的路，都變成了死路。", background: Background.Chapter_3_Ch3_Act17_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "07:13。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把訊息截圖。他知道截圖到下一輪會消失。但他還是截了。像留下一個證據——給此時此刻的自己看的證據。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他把手機放下。拿起那張紙。展開。看著表格。看著那四個字。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "07:14。宿舍走廊上傳來腳步聲。隔壁寢室的門開了。有人在打哈欠。廣播還在播。雨還在下。海還是灰的。鐘樓還在雨霧裡站著。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一切都是第四次。一切都是第一次。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但坐在這張書桌前的人，已經不是第一次的那個人了。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他不再是逃亡者。不再是試探者。", background: Background.Chapter_3_Ch3_Act17_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他開始調查了。", background: Background.Chapter_3_Ch3_Act17_S0 },
];
